// El endpoint /api/process-email retorna { success: true, eventData: {...} }
// eventData ya es un objeto JSON parseado (no texto)
const response = $input.first().json;

if (!response.success || !response.eventData) {
  return [{
    json: {
      error: true,
      message: 'Error en el endpoint: ' + JSON.stringify(response),
      rawContent: JSON.stringify(response)
    }
  }];
}

const evento = response.eventData;

if (!evento.titulo) {
  return [{
    json: {
      error: true,
      message: 'Claude no identificó evento escolar relevante',
      rawContent: JSON.stringify(evento)
    }
  }];
}

return [{
  json: {
    titulo: evento.titulo,
    tipo: evento.tipo || 'aviso',
    materia: evento.materia || 'General',
    fecha: evento.fecha || new Date().toISOString().split('T')[0],
    descripcion: evento.descripcion || '',
    estado: 'pendiente',
    origen: 'email',
    emailOrigen: $('Gmail - Detectar Email').first().json.from?.value?.[0]?.address || 'desconocido',
    createdAt: new Date().toISOString()
  }
}];
